import { useState } from 'react';
import './App.css';
import Api from './axios/api';
import { json } from 'stream/consumers';

interface Usuario {
  id: number;
  nome: string;
  cpf: string;
  telefone: string;
  status: string;
}

function App() {
const [usuarios, setUsuarios] =useState<Usuario[]>([{} as Usuario]);
const BuscarTodosUsuarios= async () => {
  console.log("Buscando todos os usuários...");
 await Api.get("",{
    params:{
    planilha:"usuario"
  }
  }
).then((response)=>setUsuarios(response.data) )  
  .catch((e)=> console.log(e));

}
return (
    <div style={{display:'flex',flexDirection:"column"}}>
      <h1>Hello Mumi Braids!</h1>
      <h4> Site de Agendamento</h4>      
    <div style={{}}>
      <div style={{display:"flex",flexDirection:"row"}}>
        <h2 style={{ margin:10}}>Nome</h2>
        <h2 style={{margin:10}}>Telefone</h2>
        <h2 style={{}}>Data Agendamento</h2>
        <h2 style={{}}>Horário</h2>
        <h2 style={{}}>Dia</h2>
      </div >
      {usuarios.map((usuario) => 
        <div style={{ display: "flex", flexDirection: "row"}}>
      <h2>{usuario.nome}</h2>
          <h2>{usuario.nome}</h2>
          <h2>{usuario.nome}</h2>  
          <h2>{usuario.nome}</h2>
          <h2>{usuario.nome}</h2>
         </div>
    )} 

     </div>

    <div>
      <button onClick={BuscarTodosUsuarios}>  Visuaisar</button>
      </div>

    </div> 
  );
}

export default App;
